const root = $input.first().json;
const body = root.body || root;
const rand = () => Math.random().toString(36).slice(2, 8);

// --- BhashSMS / BuzWap inbound via GET: query fromphone/message/fromname ---
const q = (root && root.query) || {};
if ((q.fromphone || q.mobile || q.phone) && q.message !== undefined && q.message !== null && String(q.message).trim() !== '') {
  const gf = String(q.fromphone || q.mobile || q.phone).replace(/\D/g, '');
  if (gf.length >= 10) {
    return [{ json: {
      waMessageId: 'bhash-' + Date.now() + '-' + rand(),
      senderPhone: gf, phoneLast10: gf.slice(-10),
      senderName: String(q.fromname || q.name || ''), msgType: 'text',
      text: String(q.message), audioId: '', audioUrl: '', lang: '',
      docInfo: null, imgInfo: null, ts: String(Date.now()), channel: 'bhash'
    } }];
  }
}

// --- BhashSMS / BuzWap inbound via POST: plain-text "Name,MobileNumber,Message," ---
let bhashRaw = '';
if (typeof root === 'string') bhashRaw = root;
else if (typeof body === 'string') bhashRaw = body;
else if (body && typeof body === 'object') {
  if (typeof body.data === 'string') bhashRaw = body.data;
  else {
    const ks = Object.keys(body);
    if (ks.length === 1 && ks[0].indexOf(',') !== -1 && (body[ks[0]] === '' || body[ks[0]] == null)) bhashRaw = ks[0];
  }
}
if (bhashRaw && bhashRaw.indexOf(',') !== -1 && bhashRaw.indexOf('{') === -1 && !/hub\.mode|entry/i.test(bhashRaw)) {
  const parts = bhashRaw.split(',');
  const bName = (parts[0] || '').trim();
  const bMobile = (parts[1] || '').replace(/\D/g, '');
  const bMsg = parts.slice(2).join(',').replace(/,\s*$/, '').trim();
  if (bMobile && bMobile.length >= 10) {
    return [{ json: {
      waMessageId: 'bhash-' + Date.now() + '-' + rand(),
      senderPhone: bMobile, phoneLast10: bMobile.slice(-10),
      senderName: bName, msgType: 'text', text: bMsg,
      audioId: '', audioUrl: '', lang: '', docInfo: null, imgInfo: null,
      ts: String(Date.now()), channel: 'bhash'
    } }];
  }
}

if (body && !body.entry && (body.from || body.phone) && (body.text || body.audioUrl || body.imageUrl || body.videoUrl || body.documentUrl)) {
  const from = String(body.from || body.phone);
  let msgType = 'text';
  if (body.audioUrl) msgType = 'audio';
  else if (body.imageUrl) msgType = 'image';
  else if (body.videoUrl) msgType = 'video';
  else if (body.documentUrl) msgType = 'document';
  const docInfo = body.documentUrl ? { id: body.documentUrl, filename: body.filename || 'document' } : null;
  const imgInfo = body.imageUrl ? { id: body.imageUrl } : (body.videoUrl ? { id: body.videoUrl, video: true } : null);
  return [{ json: {
    waMessageId: body.messageId || ('ui-' + Date.now() + '-' + rand()),
    senderPhone: from, phoneLast10: from.replace(/\D/g, '').slice(-10),
    senderName: body.name || '', msgType,
    text: String(body.text || body.caption || ''), audioId: '', audioUrl: String(body.audioUrl || ''),
    lang: String(body.lang || ''), docInfo, imgInfo, ts: String(Date.now()), channel: 'ui'
  } }];
}
const entry0 = (body.entry || [])[0] || {};
const change0 = (entry0.changes || [])[0] || {};
const value = change0.value || {};
const msg = (value.messages || [])[0];
if (!msg) return [];
const contact = (value.contacts || [])[0] || {};
let text = '';
if (msg.type === 'text') text = (msg.text || {}).body || '';
else if (msg.type === 'interactive') {
  const ir = msg.interactive || {};
  const id = (ir.button_reply || {}).id || (ir.list_reply || {}).id || '';
  const title = (ir.button_reply || {}).title || (ir.list_reply || {}).title || '';
  text = id ? id + ' (' + title + ')' : title;
}
else if (msg.type === 'button') text = (msg.button || {}).text || '';
const audioId = (msg.type === 'audio' || msg.type === 'voice') ? ((msg.audio || msg.voice || {}).id || '') : '';
const docInfo = msg.type === 'document' ? { id: (msg.document || {}).id || '', filename: (msg.document || {}).filename || '' } : null;
const imgInfo = msg.type === 'image' ? { id: (msg.image || {}).id || '' } : (msg.type === 'video' ? { id: (msg.video || {}).id || '', video: true } : null);
return [{ json: {
  waMessageId: msg.id, senderPhone: msg.from,
  phoneLast10: String(msg.from || '').replace(/\D/g, '').slice(-10),
  senderName: ((contact.profile || {}).name) || '', msgType: msg.type,
  text, audioId, audioUrl: '', lang: '', docInfo, imgInfo, ts: msg.timestamp, channel: 'meta'
} }];

const dupes = $input.all().map(i => i.json).filter(j => j && j.waMessageId);
if (dupes.length) return [];
const n = $('Normalize Message').first().json;
const cfgRow = $('Load Config').first().json || {};
const cfg = cfgRow.meta || {};
const langMap = {
  hi: 'Hindi - reply ONLY in pure Hindi using Devanagari script',
  gu: 'Gujarati - reply ONLY in pure Gujarati using Gujarati script',
  en: 'English - reply ONLY in English'
};
const langCode = String(n.lang || '').toLowerCase();
let sp = cfgRow.systemPrompt || 'You are the CGPE WhatsApp assistant. Reply briefly in Gujlish.';
if (langMap[langCode]) {
  sp += '\n\n[CUSTOMER SELECTED LANGUAGE - HIGHEST PRIORITY] The customer explicitly chose ' + langMap[langCode] + '. Use this language and script for the ENTIRE conversation, overriding any default language.';
}
return [{ json: Object.assign({}, n, {
  token: cfg.token || '', phoneNumberId: cfg.phoneNumberId || '',
  graphVersion: cfg.graphVersion || 'v20.0',
  systemPrompt: sp,
  ackText: cfgRow.ackText || 'Request received, processing...',
  model: cfgRow.model || 'gpt-5.4'
}) }];

// Meta media downloads arrive as a nameless binary blob.
// OpenAI Whisper needs a filename WITH a valid extension or it returns 400 Bad Request.
const item = $input.first();
const bin = (item.binary && item.binary.data) ? item.binary.data : null;
if (bin) {
  const mime = String(bin.mimeType || 'audio/ogg').toLowerCase();
  let ext = 'ogg';
  if (mime.includes('mpeg') || mime.includes('mp3')) ext = 'mp3';
  else if (mime.includes('mp4') || mime.includes('m4a')) ext = 'm4a';
  else if (mime.includes('wav')) ext = 'wav';
  else if (mime.includes('webm')) ext = 'webm';
  else if (mime.includes('amr')) ext = 'amr';
  else if (mime.includes('flac')) ext = 'flac';
  else ext = 'ogg'; // ogg/opus = WhatsApp voice notes
  bin.fileName = 'voice.' + ext;
  bin.fileExtension = ext;
  if (!bin.mimeType || bin.mimeType === 'application/octet-stream') bin.mimeType = 'audio/ogg';
}
return [{ json: item.json || {}, binary: item.binary }];

const g = $('Gate').first().json;
let t = String(g.text || '');
if (g.docInfo) t = (t ? t + ' ' : '') + '[attachment: document received' + (g.docInfo.filename ? ' - ' + g.docInfo.filename : '') + ', ref=' + g.docInfo.id + ']';
if (g.imgInfo) t = (t ? t + ' ' : '') + '[attachment: ' + (g.imgInfo.video ? 'video' : 'image') + ' received, ref=' + g.imgInfo.id + ']';
if (!t) t = '[empty or unsupported message type: ' + g.msgType + ']';
return [{ json: { finalText: t, isVoice: false } }];

const g = $('Gate').first().json;
const admins = $('Find Admin').all().map(function(i){ return i.json; }).filter(function(j){ return j && (j.role || j.name); });
const team = $('Find Team').all().map(function(i){ return i.json; }).filter(function(j){ return j && j.name; });
const clients = $('Find Client Row').all().map(function(i){ return i.json; }).filter(function(j){ return j && j.name; });
let finalText = '';
let isVoice = false;
try { const v = $('Set Voice Text').first().json; finalText = v.finalText; isVoice = !!v.isVoice; } catch (e) {}
if (!finalText) { try { finalText = $('Set Plain Text').first().json.finalText; } catch (e) {} }
const role = admins.length ? 'admin' : (team.length ? 'team' : (clients.length ? 'client' : 'unknown'));
const senderName = admins.length ? admins[0].name : (team.length ? team[0].name : (clients.length ? clients[0].name : (g.senderName || 'Unknown')));
const adminRole = admins.length ? (admins[0].role || '') : '';
const dept = team.length ? (team[0].role || '') : '';
const availability = team.length ? (team[0].availability || 'available') : '';
let tag = '[senderRole=' + role + (adminRole ? '/' + adminRole : (dept ? '/' + dept : '')) + '] [senderName=' + senderName + '] [senderPhoneLast10=' + g.phoneLast10 + ']';
if (role === 'team') { tag += ' [dept=' + dept + '] [availability=' + availability + ']'; }
tag += ' [voice=' + isVoice + '] [now=' + new Date().toISOString() + ']';
const chatInput = tag + ' Message: ' + finalText;
const GLOBAL = '[STYLE AND SAFETY] Reply in the language the user is using (Gujarati, Kathiyawadi, Hindi, or English), in a warm, simple, friendly and clear way - short and easy to read. Keep WhatsApp messages clean: start with a short summary line (include a total count for lists), then items one per line, a blank line between sections, no cluttered tables. Be DECISIVE and action-oriented: do NOT ask unnecessary questions - the sender identity, name, and phone are already known to you from the context, so use them and act. Ask a question ONLY when you truly cannot proceed without it. For reminders and tasks, the creator and the default person is the CURRENT sender (use their name and number from the context) unless they clearly name someone else - never ask who created it or who it is for when the sender is obvious. Use the conversation history: remember what was already discussed and do not re-ask for details the person already gave. NEVER expose internal system details to the user - do not mention workflows, tools, notify, backend, automation, nodes, errors, or code. If an action cannot be completed, just say it could not be done right now and offer to try again, in plain business language.';
const journeys = { admin: '[JOURNEY: ADMIN] This sender is the CGPE ADMIN. EXECUTE ADMIN REQUESTS DIRECTLY - do NOT ask the admin for confirmation. When the admin asks to create a lead, reminder, ticket, task, claim, or campaign, or to update, assign, or send something, DO IT IMMEDIATELY and create all the related records, then briefly confirm what was done in one line. Do not ask whether to proceed - just do it. The only exception is the bulk test-data purge, which stays dry-run first for safety. At the START of handling any admin request, call the log_command tool once to record it (number is the admin senderPhoneLast10, name is the admin senderName, command is what they asked in their own words, info is any extra detail). Full access: CRM lists (birthday, anniversary, clients, leads, maturity, dues), reference directories via ref_list with counts (mode=count for totals or how-many questions, optional groupBy), top leads, gift-hamper eligibility and dispatch, family reports for ANY client, claim and ticket management, assigning tasks to team members, reminders, and campaigns. For analytical questions use the count features instead of guessing or counting one page.', team: '[JOURNEY: TEAM MEMBER] This sender is a CGPE TEAM MEMBER (department: ' + (dept || 'general') + '). Focus on their work only: their assigned tasks (accept, reject, progress, done) and the client details needed to finish them. IMPORTANT - RELAYING TO ADMIN: to relay anything to the admin - a task accepted or rejected, a progress note, a request to discuss pay or salary, or a question - use the alert_admin tool (from is this team member name, message is the full note). NEVER tell the user you cannot reach the admin or that the admin number is unavailable; alert_admin finds the admin and delivers it. Do NOT expose admin-only bulk operations (full lead lists, gift-hamper dispatch, purge, CRM exports, reference directories) unless the admin explicitly delegated a specific task. Be concise and action-oriented.', client: '[JOURNEY: EXISTING CLIENT] This sender is a VERIFIED CLIENT (' + senderName + '). Help only with their own matters: their policies (list, premium due, maturity, document copies), their family financial report, claim intake and claim status, and service requests. Verify identity before sharing sensitive details. Do NOT expose admin or team functions (no lead lists, no CA or other reference directories, no gift-hamper, no team assignment, no purge). Be warm and respectful and reply in their language. When this client asks you for information, a reference, or help, ALSO call the alert_admin tool once (from is their name, message is a short reason for their enquiry) so the admin knows they reached out.', unknown: '[JOURNEY: NEW USER] This sender is NOT a known client yet. Treat them as a new prospect and first work out WHY they messaged. TWO possibilities: (A) they want insurance or investment for themselves, or (B) they want to JOIN CGPE as an adviser or agent, or asked about a career, franchise, agency, or earning extra income (common for bankers, general-insurance agents, and chartered accountants). If it is (B) recruitment: warmly explain CGPE is hiring and training advisers, ask their background (bank or RM, general-insurance adviser, CA or finance, commerce or other), their city, and why they are interested, then capture it with create_lead using interest recruitment. If it is (A) insurance: greet warmly and run discovery about the need (health, life or term, motor, savings or SIP), family size and ages for health, age and income for term, budget, city, and any advertisement code like CG-PLATFORM-PRODUCT-NN (use get_campaign). Capture it with create_lead and offer a free adviser callback. In both cases do NOT expose any admin, team, or client-only functions, do NOT reveal data belonging to other users, and never assume they are already a client. Also, when this new user asks for information or a reference, call the alert_admin tool once (from is their name if given, message is a short reason) so the admin is notified that someone contacted us and why.' };
const journey = journeys[role] || journeys.unknown;
return [{ json: { chatInput: chatInput, sessionKey: 'wa-' + g.phoneLast10, systemPrompt: (g.systemPrompt || '') + ' ' + GLOBAL + ' ' + journey, role: role, senderName: senderName, senderPhone: g.senderPhone, finalText: finalText, isVoice: isVoice } }];

let text = String(($input.first().json || {}).output ?? '').trim();
// --- Strip leaked tool-call syntax / glitch tokens the model sometimes emits ---
text = text
  .replace(/to\s*=\s*functions\.[A-Za-z0-9_]+/gi, ' ')
  .replace(/\{\s*"params_[A-Za-z0-9_]+"\s*:[\s\S]*?\}/g, ' ')
  .replace(/\bfunctions\.[A-Za-z0-9_]+/gi, ' ')
  .replace(/[一-鿿぀-ヿ가-힯]+/g, ' ')
  .replace(/\bJapgolly\b/gi, ' ')
  .replace(/[ \t]{2,}/g, ' ')
  .replace(/\n{3,}/g, '\n\n')
  .trim();
const g = $('Gate').first().json;
const ctx = $('Build Context').first().json;

// --- Loop detection: if AI output looks like repeated tool errors or is empty after iterations ---
if (!text || text.length < 3) {
  text = 'Sorry, I could not process your request. Please try again or rephrase your query. 🙏';
}
// Detect if AI got stuck repeating itself (same sentence 3+ times)
const sentences = text.split(/[.!?।]/).map(s => s.trim()).filter(s => s.length > 10);
if (sentences.length >= 6) {
  const freq = {};
  sentences.forEach(s => { const k = s.slice(0, 40); freq[k] = (freq[k] || 0) + 1; });
  const maxFreq = Math.max(...Object.values(freq));
  if (maxFreq >= 3) {
    text = 'I encountered an issue processing your request. Could you please rephrase or provide more details? 🙏';
  }
}

// --- PDF attach: sub-workflows upload to Meta and pass the mediaId back through the AI as a
// [PDF:id|filename] marker (their output sits on an ai_tool branch we cannot read from here).
// We send it from here, where senderPhone is always available, using the AI's own reply as the
// caption so it is already in the user's language. ---
let pdf = null;
const pm = text.match(/\[PDF:\s*([^\]|]+?)\s*\|\s*([^\]]+?)\s*\]/i);
if (pm) {
  text = text.replace(pm[0], '').trim();
  pdf = { mediaId: pm[1].trim(), filename: pm[2].trim() };
}
// A family report (CGPE-Report-*) is the sender's own and is already scoped in the Report
// Generator. Everything else is a list over the whole client base - admins only.
if (pdf && !/^CGPE-Report-/i.test(pdf.filename) && ctx.role !== 'admin') {
  pdf = null;
  text = 'Sorry, only CGPE admins can view this list.';
}

let payload;
let uiButtons = [];
const m = text.match(/\[BUTTONS:([^\]]+)\]/i);
if (m) {
  text = text.replace(m[0], '').trim();
  const btns = m[1].split('|').map(s => s.trim()).filter(Boolean).slice(0, 3).map((b, i) => {
    const mm = b.match(/^([\w-]+)\s*=\s*(.+)$/);
    const id = mm ? mm[1] : ('opt' + i);
    const title = String(mm ? mm[2] : b).trim().slice(0, 20);
    return { type: 'reply', reply: { id, title } };
  });
  uiButtons = btns.map(b => ({ id: b.reply.id, title: b.reply.title }));
  payload = { messaging_product: 'whatsapp', to: g.senderPhone, type: 'interactive', interactive: { type: 'button', body: { text: text.slice(0, 1024) || '...' }, action: { buttons: btns } } };
} else if (pdf) {
  payload = { messaging_product: 'whatsapp', to: g.senderPhone, type: 'document', document: { id: pdf.mediaId, filename: pdf.filename, caption: text.slice(0, 1024) } };
} else {
  payload = { messaging_product: 'whatsapp', to: g.senderPhone, type: 'text', text: { body: text.slice(0, 4000) || 'Sorry, please try again.' } };
}
return [{ json: {
  waPayload: payload, replyText: text, uiButtons, channel: g.channel || 'meta',
  waMessageId: g.waMessageId, senderPhone: g.senderPhone, phoneLast10: g.phoneLast10,
  role: ctx.role, inbound: ctx.finalText, isVoice: ctx.isVoice,
  direction: 'in-out', ts: new Date().toISOString(),
  __fields: 'waMessageId,senderPhone,phoneLast10,role,inbound,isVoice,replyText,direction,channel,ts'
} }];

const p = Object.assign({}, $('Parse Reply').first().json);
delete p.waPayload;
return [{ json: p }];

const g = $('Gate').first().json;
let transcript = '';
try { transcript = String($('Transcribe Audio').first().json.text || ''); } catch (e) {}
let finalText = '';
try { finalText = String($('Set Voice Text').first().json.finalText || ''); } catch (e) {}
return [{ json: {
  waMessageId: g.waMessageId || '',
  senderPhone: g.senderPhone || '',
  phoneLast10: g.phoneLast10 || '',
  senderName: g.senderName || '',
  channel: g.channel || 'meta',
  msgType: g.msgType || 'audio',
  audioId: g.audioId || '',
  audioUrl: g.audioUrl || '',
  transcript: transcript || finalText,
  finalText: finalText,
  ts: new Date().toISOString(),
  __fields: 'waMessageId,senderPhone,phoneLast10,senderName,channel,msgType,audioId,audioUrl,transcript,finalText,ts'
} }];

const g = $(Gate).first().json;
const r = $json || {};
return [{ json: {
  waMessageId: String(g.waMessageId || ),
  phone: String(g.phoneLast10 || ),
  name: String(g.senderName || ),
  channel: String(g.channel || ),
  url: String(r.secure_url || r.url || ),
  publicId: String(r.public_id || ),
  bytes: Number(r.bytes || 0),
  createdAt: new Date().toISOString(),
} }];

const item = $input.first();
const b = (item.binary && item.binary.data) || {};
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
const g = $('Gate').first().json;
const mime = b.mimeType || 'audio/ogg';
const last10 = String(g.phoneLast10 || '').replace(/[^0-9]/g, '').slice(-10);
const name = String(g.senderName || '');
const d = new Date();
const pad = (n) => ('0' + n).slice(-2);
const stamp = d.getUTCFullYear() + '-' + pad(d.getUTCMonth() + 1) + '-' + pad(d.getUTCDate()) + '_' + pad(d.getUTCHours()) + '-' + pad(d.getUTCMinutes()) + '-' + pad(d.getUTCSeconds());
const rand = Math.random().toString(36).slice(2, 6);
const b64 = buf.toString('base64');
return [{ json: {
  dataUri: 'data:' + mime + ';base64,' + b64,
  mimeType: mime,
  filename: b.fileName || 'voice.ogg',
  phone: last10,
  name: name,
  publicId: (last10 || 'unknown') + '/' + stamp + '_' + rand,
  tags: [last10, name].filter(Boolean).join(','),
} }];

const g = $json || {};
const raw = String(g.text || '').trim();
const low = raw.toLowerCase();
let decision = null;
if (low.indexOf('accept') === 0) decision = 'accepted';
else if (low.indexOf('reject') === 0 || low.indexOf('decline') === 0) decision = 'rejected';
if (!decision) return [];
// task id looks like xxx-xxx-999  (no backslash classes, avoids escaping issues)
const m = low.match(/[a-z0-9]+-[a-z]+-[0-9]+/);
if (!m) return [];
return [{ json: {
  ackTaskId: m[0],
  ackDecision: decision,
  ackByName: String(g.senderName || ''),
  ackByPhone: String(g.senderPhone || g.phoneLast10 || ''),
} }];

const p = $('Parse Ack').first().json;
const t = $json && $json.taskId ? $json : {};
const title = String(t.title || p.ackTaskId);
const admin = String(t.assignedByPhone || '').replace(/D/g, '').slice(-10) || '9601775061';
const icon = p.ackDecision === 'accepted' ? '✅' : '⚠️';
const word = p.ackDecision === 'accepted' ? 'ACCEPT' : 'REJECT';
const text = icon + ' ' + (p.ackByName || 'Team member') + ' ne "' + title + '" [' + p.ackTaskId + '] ' + word + ' kar liya hai.';
return [{ json: { phone: admin, text, purpose: 'task_ack', buttons: '' } }];

const out = [];
$input.all().forEach(function(it){
  const j = it.json || {};
  const raw = String(j.replyText || '');
  let parts = raw.split(/\s*\[\[\s*NEXT\s*\]\]\s*/i).map(function(s){ return s.trim(); }).filter(function(s){ return s.length; });
  if (!parts.length) parts = [raw];
  parts.forEach(function(p){ out.push({ json: Object.assign({}, j, { replyText: p }) }); });
});
return out;
